-- Seed data for Playrunners database
USE playrunners;
-- Seed Games
INSERT INTO games (id, title, tagline, description, genre, price, image_url, cover_banner, rating, release_date, publisher, developer, sys_req_min, sys_req_rec) VALUES
(1, 'Cyber Reckoning: Neon Protocol', 'Unleash cybernetic chaos in the neon-drenched grid.', 'Enter a futuristic cityscape ruled by mega-corporations. Play as a rogue hacker-mercenary fighting for survival and digital freedom in this fast-paced action cyber-RPG. Customize your implants, upgrade your arsenal, and rewrite the system.', 'RPG', 59.99, 'https://images.unsplash.com/photo-1542751371-adc38448a05e?q=80&w=600&auto=format&fit=crop', 'https://images.unsplash.com/photo-1607604276583-eef5d076aa5f?q=80&w=1200&auto=format&fit=crop', 4.8, '2026-03-10', 'Nexus Interactive', 'Neon Void Studios', 'OS: Windows 10 | CPU: Intel Core i5-8400 | RAM: 8 GB | GPU: GTX 1060 6GB | Storage: 50 GB', 'OS: Windows 11 | CPU: Intel Core i7-10700 | RAM: 16 GB | GPU: RTX 3070 | Storage: 50 GB SSD'),
(2, 'Shadow Protocol: Apex', 'Ghost through the dark. Strike with lethal precision.', 'A tactical stealth-action shooter set in geopolitical shadow conflicts. Execute silent takedowns, use high-tech gadgets, and slip through enemy defenses undetected. Coordinate with your team in co-op mode or go lone wolf in the campaign.', 'Action', 29.99, 'https://images.unsplash.com/photo-1511512578047-dfb367046420?q=80&w=600&auto=format&fit=crop', 'https://images.unsplash.com/photo-1538481199705-c710c4e965fc?q=80&w=1200&auto=format&fit=crop', 4.5, '2025-11-20', 'Ghostworks Entertainment', 'Shadow Lab Labs', 'OS: Windows 10 | CPU: AMD Ryzen 3 3100 | RAM: 8 GB | GPU: GTX 1050 Ti | Storage: 35 GB', 'OS: Windows 10/11 | CPU: AMD Ryzen 5 5600X | RAM: 16 GB | GPU: RTX 2060 | Storage: 35 GB SSD'),
(3, 'Xenon Vanguard', 'Fast-paced arena shooter with high stakes.', 'Dominate the arena in a hero-based tactical shooter. Customize your loadout with futuristic gadgets, weapon modifiers, and coordinate synergy with teammates in standard 5v5 competitive queues or active clan wars.', 'Shooter', 39.99, 'https://images.unsplash.com/photo-1552820728-8b83bb6b773f?q=80&w=600&auto=format&fit=crop', 'https://images.unsplash.com/photo-1542751371-adc38448a05e?q=80&w=1200&auto=format&fit=crop', 4.2, '2026-01-15', 'Playrunners Games', 'Vector Forge Studio', 'OS: Windows 10 | CPU: Intel i3-6100 | RAM: 8 GB | GPU: GTX 960 | Storage: 20 GB', 'OS: Windows 11 | CPU: Intel i5-11400 | RAM: 16 GB | GPU: GTX 1660 Super | Storage: 20 GB SSD'),
(4, 'Star Hunter: Orion', 'Explore the uncharted edges of the galaxy.', 'An open-world space exploration simulator combined with tactical dogfights and resource trading. Pilot a variety of customizable starships, build space outposts, join factions, and chart new solar systems in a massive multiplayer universe.', 'Adventure', 49.99, 'https://images.unsplash.com/photo-1509198397868-475647b2a1e5?q=80&w=600&auto=format&fit=crop', 'https://images.unsplash.com/photo-1579546929518-9e396f3cc809?q=80&w=1200&auto=format&fit=crop', 4.6, '2025-08-04', 'Starlight Studios', 'CosmoSoft', 'OS: Windows 10 | CPU: Intel i5-9600K | RAM: 12 GB | GPU: GTX 1660 | Storage: 60 GB SSD', 'OS: Windows 11 | CPU: Intel i7-12700K | RAM: 32 GB | GPU: RTX 3080 | Storage: 60 GB NVMe'),
(5, 'Apex Drift: Heat', 'Burn rubber and escape the law in street races.', 'High-octane arcade racing with stunning visual fidelity and deep vehicle customization. Race through city streets, winding mountains, and seaside highways while dodging rival drivers and high-speed police chases.', 'Racing', 19.99, 'https://images.unsplash.com/photo-1511919884226-fd3cad34687c?q=80&w=600&auto=format&fit=crop', 'https://images.unsplash.com/photo-1518173946687-a4c8a383392e?q=80&w=1200&auto=format&fit=crop', 4.4, '2024-05-18', 'Drift Nation Inc', 'Velocity Lab', 'OS: Windows 10 | CPU: AMD FX-6300 | RAM: 8 GB | GPU: Radeon HD 7850 | Storage: 25 GB', 'OS: Windows 10/11 | CPU: AMD Ryzen 5 2600 | RAM: 12 GB | GPU: GTX 1650 Super | Storage: 25 GB SSD'),
(6, 'Primal Carnage', 'Survive in a world reclaimed by prehistoric beasts.', 'A sandbox survival crafting game. Awaken on a mysterious island crawling with dinosaurs and prehistoric monsters. Gather materials, build shelters, craft weapons, domesticate creatures, and form tribes with other survivors to dominate the wilderness.', 'Indie', 14.99, 'https://images.unsplash.com/photo-1534447677768-be436bb09401?q=80&w=600&auto=format&fit=crop', 'https://images.unsplash.com/photo-1500628550463-c8881a54d4d4?q=80&w=1200&auto=format&fit=crop', 4.7, '2024-10-02', 'Primal Craft Games', 'Stone Age Studios', 'OS: Windows 10 | CPU: Intel Core i5-4460 | RAM: 8 GB | GPU: GTX 760 | Storage: 15 GB', 'OS: Windows 10/11 | CPU: Intel Core i7-4770 | RAM: 16 GB | GPU: GTX 1060 6GB | Storage: 15 GB SSD');
