INSERT INTO tournaments (id, title, subtitle, prize_pool, status, start_date, image_url, rulebook) VALUES
(1, 'Nexus Champions Invitational', 'The pinnacle of Cyber Reckoning competitive play.', '$250,000', 'ongoing', '2026-07-15', 'https://images.unsplash.com/photo-1560253023-3ec5d502959f?q=80&w=600&auto=format&fit=crop', 'Official rules: 5v5 team format, double elimination bracket. Single-hero lock, standard maps only. All players must check in 30 minutes before match time.'),
(2, 'Pro League Championship', 'The official professional tournament for Shadow Protocol.', '$100,000', 'upcoming', '2026-08-01', 'https://images.unsplash.com/photo-1511512578047-dfb367046420?q=80&w=600&auto=format&fit=crop', 'Official rules: Squad tactical search and destroy. 4v4 format. Pro league map pool. No glitching, exploits or unapproved scripts.'),
(3, 'Clash of Titans: Arena', 'Community showdown for Xenon Vanguard.', '$50,000', 'completed', '2026-06-10', 'https://images.unsplash.com/photo-1542751371-adc38448a05e?q=80&w=600&auto=format&fit=crop', 'Community open bracket. Single elimination. Top 3 teams receive cash prizes.');
